SELECT MAX(base_salary) AS max_base_salary
FROM compensation
WHERE year = 2015;

SELECT job_family_name
FROM job_families
WHERE overtime_eligibility = 1;

SELECT COUNT(employee_id) AS active_employees
FROM employee_status
WHERE status = 'active';

SELECT employee_id, benefit_amount
FROM benefit_history
WHERE year = 2015;

SELECT SUM(benefit_amount) AS total_retirement_benefit
FROM benefit_history
WHERE benefit_type = 'retirement' AND year = 2015;

SELECT status
FROM employee_status
WHERE status = 'active';
